examples.original_ir:
declare i32 @llvm.cttz.i32(i32, i1 immarg)

define i32 @test(i32 %x) {
  %tz = call noundef i32 @llvm.cttz.i32(i32 %x, i1 false)
  %shl = shl i32 1, %tz
  ret i32 %shl
}

examples.optimized_ir:
declare i32 @llvm.cttz.i32(i32, i1 immarg)

define i32 @test(i32 %x) {
  %tz = call noundef i32 @llvm.cttz.i32(i32 %x, i1 true)
  %shl = shl i32 1, %tz
  ret i32 %shl
}
